function calculateResilience(inputs) {
  const { 
    avg_asset_age_years, 
    maintenance_spending_pct_of_replacement_value, 
    redundancy_level_pct, 
    critical_failure_points_count, 
    historical_disaster_frequency_per_decade, 
    mean_time_to_recovery_hours, 
    interdependency_complexity_score, 
    hazard_exposure_vulnerability_score 
  } = inputs;

  // Ensure all inputs are numbers and apply default/cap if necessary (though inputs are required, for robustness)
  const age = Math.max(0, parseFloat(avg_asset_age_years) || 0);
  const maintenance = Math.max(0, parseFloat(maintenance_spending_pct_of_replacement_value) || 0);
  const redundancy = Math.max(0, Math.min(100, parseFloat(redundancy_level_pct) || 0));
  const criticalPoints = Math.max(0, parseFloat(critical_failure_points_count) || 0);
  const disasterFreq = Math.max(0, parseFloat(historical_disaster_frequency_per_decade) || 0);
  const mtr = Math.max(0, parseFloat(mean_time_to_recovery_hours) || 0);
  const interdependency = Math.max(1, Math.min(10, parseFloat(interdependency_complexity_score) || 1));
  const hazardExposure = Math.max(1, Math.min(10, parseFloat(hazard_exposure_vulnerability_score) || 1));

  // Calculate normalized sub-scores (0-100, higher = better resilience)

  // 1. Age Score: Older assets reduce resilience. Max age for '0' score set at 100 years.
  // Score = (100 - age) / 100 * 100. Capped at 0-100.
  const scoreAge = Math.max(0, Math.min(100, (100 - age)));

  // 2. Maintenance Score: Higher spending improves resilience. 2.5% of replacement value considered excellent.
  // Score = (maintenance / 2.5) * 100. Capped at 0-100.
  const scoreMaintenance = Math.max(0, Math.min(100, (maintenance / 2.5) * 100));

  // 3. Redundancy Score: Directly proportional to percentage. Capped at 0-100.
  const scoreRedundancy = redundancy;

  // 4. Critical Failure Points Score: Fewer points improve resilience. 10 points or more is a '0' score.
  // Score = (10 - criticalPoints) / 10 * 100. Capped at 0-100.
  const scoreCriticalPoints = Math.max(0, Math.min(100, (10 - criticalPoints) / 10 * 100));

  // 5. Disaster Frequency Score: Lower frequency improves resilience. 10 events/decade or more is '0' score.
  // Score = (10 - disasterFreq) / 10 * 100. Capped at 0-100.
  const scoreDisasterFreq = Math.max(0, Math.min(100, (10 - disasterFreq) / 10 * 100));

  // 6. Mean Time to Recovery (MTR) Score: Shorter MTR improves resilience. 168 hours (1 week) or more is '0' score.
  // Score = (168 - mtr) / 168 * 100. Capped at 0-100.
  const scoreMTR = Math.max(0, Math.min(100, (168 - mtr) / 168 * 100));

  // 7. Interdependency Complexity Score: Lower complexity (score of 1) means better resilience (100 score).
  // Score = (10 - interdependency) / 9 * 100. Capped at 0-100.
  const scoreInterdependency = Math.max(0, Math.min(100, (10 - interdependency) / 9 * 100));

  // 8. Hazard Exposure & Vulnerability Score: Lower exposure (score of 1) means better resilience (100 score).
  // Score = (10 - hazardExposure) / 9 * 100. Capped at 0-100.
  const scoreHazardExposure = Math.max(0, Math.min(100, (10 - hazardExposure) / 9 * 100));

  // Define weights for each factor (sum should be 1.0)
  const weights = {
    age: 0.125,
    maintenance: 0.175,
    redundancy: 0.15,
    criticalPoints: 0.125,
    disasterFreq: 0.10,
    mtr: 0.125,
    interdependency: 0.10,
    hazardExposure: 0.10
  };

  // Calculate the composite resilience score
  let composite_resilience_score = (
    scoreAge * weights.age +
    scoreMaintenance * weights.maintenance +
    scoreRedundancy * weights.redundancy +
    scoreCriticalPoints * weights.criticalPoints +
    scoreDisasterFreq * weights.disasterFreq +
    scoreMTR * weights.mtr +
    scoreInterdependency * weights.interdependency +
    scoreHazardExposure * weights.hazardExposure
  );

  // Ensure score is within 0-100 range
  composite_resilience_score = Math.max(0, Math.min(100, composite_resilience_score));

  // Determine Resilience Rating
  let resilience_rating;
  if (composite_resilience_score >= 85) {
    resilience_rating = "Excellent Resilience";
  } else if (composite_resilience_score >= 70) {
    resilience_rating = "Good Resilience";
  } else if (composite_resilience_score >= 50) {
    resilience_rating = "Moderate Resilience";
  } else if (composite_resilience_score >= 30) {
    resilience_rating = "Needs Improvement";
  } else {
    resilience_rating = "Critical Risk";
  }

  return {
    composite_resilience_score: composite_resilience_score,
    resilience_rating: resilience_rating
  };
}
